module top_module(
    input clk,
    input reset,
    input [1:0] operation,
    input [7:0] operand1,
    input [7:0] operand2,
    output [7:0] result
);reg [7:0] intermediate_value;

always @(posedge clk) begin
    if (reset) begin
        intermediate_value <= 8'h00;
    end else begin
        case (operation)
            2'b00: intermediate_value <= operand1 + operand2;
            2'b01: intermediate_value <= operand1 - operand2;
        endcase
    end
end

assign result = intermediate_value;

endmodule
